map "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/WorkSocQuestionnaireResponseToObservation" = "WorkSocQuestionnaireResponseToObservation"

/// url = "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/WorkSocQuestionnaireResponseToObservation"
/// name = "WorkSocQuestionnaireResponseToObservation"
/// title = "Work-SoC Q score to O score"
/// status = "active"

uses "http://hl7.org/fhir/StructureDefinition/QuestionnaireResponse" alias QR as source
uses "http://hl7.org/fhir/StructureDefinition/Observation" alias Obs as target

imports "http://hl7.org/fhir/StructureMap/*"
imports "https://fhir.hl7.at/prenudge/appdata/r4/StructureMap/QuestionnaireResponseToObservationBase"

group WorkSocQuestionnaireResponseToObservation(source src : QR, target tgt : Obs) {
src then SetObservationBase(src, tgt) "Base";

src -> tgt.meta as meta,
meta.profile = 'https://fhir.hl7.at/prenudge/appdata/r4/StructureDefinition/at-prenudge-work-soc-score-observation' "SetProfile";

src -> tgt.code = cc('https://fhir.hl7.at/prenudge/appdata/r4/CodeSystem/prenudge-workability', 'work-soc-category-score', 'Work-SoC category score') "SetCode";

src.item as workSocGroup where linkId = 'work-soc' then {
  workSocGroup.item as scoreGroup where linkId = 'work-soc-scores' then {
    scoreGroup.item as scoreItem where linkId = 'work-soc-comprehensibility-score'
    then MapComprehensibilityScore(scoreItem, tgt) "MapComprehensibilityScore";

    scoreGroup.item as scoreItem where linkId = 'work-soc-manageability-score'
    then MapManageabilityScore(scoreItem, tgt) "MapManageabilityScore";

    scoreGroup.item as scoreItem where linkId = 'work-soc-meaningfulness-score'
    then MapMeaningfulnessScore(scoreItem, tgt) "MapMeaningfulnessScore";
  } "ProcessWorkSocScores";
} "ProcessWorkSoc";

// TODO: Comment/Note mapping disabled due to MaLaC-HD limitation
// See: https://gitlab.com/cdehealth/malac-hd/-/issues/128
}

group MapComprehensibilityScore(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    answer.valueDecimal as val then {
      val.value as numVal -> tgt.component as comp,
      comp.code = cc('https://fhir.hl7.at/prenudge/appdata/r4/CodeSystem/prenudge-workability', 'work-soc-comprehensibility', 'Work-SoC comprehensibility score'),
      comp.value = create('Quantity') as qty,
      qty.value = numVal, qty.unit = 'score',
      qty.system = 'http://unitsofmeasure.org', qty.code = '{score}' "SetComponent";
    } "ExtractValue";
  } "ProcessAnswer";
}

group MapManageabilityScore(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    answer.valueDecimal as val then {
      val.value as numVal -> tgt.component as comp,
      comp.code = cc('https://fhir.hl7.at/prenudge/appdata/r4/CodeSystem/prenudge-workability', 'work-soc-manageability', 'Work-SoC manageability score'),
      comp.value = create('Quantity') as qty,
      qty.value = numVal, qty.unit = 'score',
      qty.system = 'http://unitsofmeasure.org', qty.code = '{score}' "SetComponent";
    } "ExtractValue";
  } "ProcessAnswer";
}

group MapMeaningfulnessScore(source src : QR, target tgt : Obs) {
  src.answer as answer then {
    answer.valueDecimal as val then {
      val.value as numVal -> tgt.component as comp,
      comp.code = cc('https://fhir.hl7.at/prenudge/appdata/r4/CodeSystem/prenudge-workability', 'work-soc-meaningfulness', 'Work-SoC meaningfulness score'),
      comp.value = create('Quantity') as qty,
      qty.value = numVal, qty.unit = 'score',
      qty.system = 'http://unitsofmeasure.org', qty.code = '{score}' "SetComponent";
    } "ExtractValue";
  } "ProcessAnswer";
}